import{_ as s,o as e,c as n,ag as l}from"./chunks/framework.DXGyWiRo.js";const y=JSON.parse('{"title":"Version Binding","description":"","frontmatter":{},"headers":[],"relativePath":"lang/version-binding.md","filePath":"lang/version-binding.md"}'),o={name:"lang/version-binding.md"};function t(i,a,p,r,c,d){return e(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="version-binding" tabindex="-1">Version Binding <a class="header-anchor" href="#version-binding" aria-label="Permalink to &quot;Version Binding&quot;">​</a></h1><p><em>Explicitly bind queries to specific schema versions.</em></p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#89DDFF;"> *</span><span style="color:#F78C6C;"> FROM</span><span style="color:#BABED8;"> public.users@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">3</span></span></code></pre></div><blockquote><p>Only available currently in FlashQL. Comming soon to PostgreSQL, and MySQL/MariaDB</p></blockquote><hr><h2 id="semver-style-matching" tabindex="-1">Semver-Style Matching <a class="header-anchor" href="#semver-style-matching" aria-label="Permalink to &quot;Semver-Style Matching&quot;">​</a></h2><p>Version binding uses semver-style matching semantics. What that means is that the matcher understands:</p><ul><li>exact matches like <code>@=3</code> or <code>@=3_4</code></li><li>comparison operators like <code>@&gt;=2</code></li><li>compatible-range operators like <code>@^2_1</code></li><li>minor/patch range operators like <code>@~7_6</code></li></ul><p>Version parts may be written only with <code>_</code> as separator:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">public.users@^2_1</span></span>
<span class="line"><span style="color:#BABED8;">public.users@3</span></span>
<span class="line"><span style="color:#BABED8;">public.users@3_4</span></span></code></pre></div><p>The bare forms are range-like too:</p><ul><li><code>@3</code> means &quot;any <code>3.x.x</code> relation version&quot;</li><li><code>@3_4</code> means &quot;any <code>3.4.x</code> relation version&quot;</li><li><code>@=3_4_1</code> means &quot;exactly <code>3.4.1</code>&quot;</li></ul><hr><h2 id="join-example" tabindex="-1">Join Example <a class="header-anchor" href="#join-example" aria-label="Permalink to &quot;Join Example&quot;">​</a></h2><p>Version binding becomes especially valuable when multiple relations participate in a query.</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span></span>
<span class="line"><span style="color:#BABED8;">  a.id,</span></span>
<span class="line"><span style="color:#BABED8;">  b.name</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.vja@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#F78C6C;"> AS</span><span style="color:#BABED8;"> a</span></span>
<span class="line"><span style="color:#F78C6C;">LEFT JOIN</span><span style="color:#BABED8;"> public.vjb@</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#F78C6C;"> AS</span><span style="color:#BABED8;"> b</span></span>
<span class="line"><span style="color:#F78C6C;">  ON</span><span style="color:#BABED8;"> a.rel </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> b.id</span></span></code></pre></div><p>How to read this:</p><ul><li>the query expects <code>public.vja</code> at relation version <code>1</code></li><li>the query expects <code>public.vjb</code> at relation version <code>1</code></li><li>if either side no longer satisfies that contract, the query should not silently continue as if nothing changed</li></ul><hr><h2 id="why-version-binding" tabindex="-1">Why Version Binding <a class="header-anchor" href="#why-version-binding" aria-label="Permalink to &quot;Why Version Binding&quot;">​</a></h2><p>Most schema drift bugs are painful because they fail too late:</p><ul><li>a query still parses</li><li>a deployment still boots</li><li>but the semantics the application assumed are no longer true</li></ul><p>Version binding gives you a way to express:</p><blockquote><p>&quot;This query is coupled to this relation version. If the storage side has moved, fail visibly.&quot;</p></blockquote><hr><h2 id="what-version-binding-is-not" tabindex="-1">What Version Binding Is Not <a class="header-anchor" href="#what-version-binding-is-not" aria-label="Permalink to &quot;What Version Binding Is Not&quot;">​</a></h2><p>Version binding is <strong>not</strong> the same thing as historical row snapshotting.</p><p>It does <strong>not</strong> mean:</p><ul><li>&quot;show me the rows as they were when version 3 existed&quot;</li></ul><p>It means:</p><ul><li>&quot;run this query only if the relation version assumptions are satisfied&quot;</li></ul><p>For historical replay, use FlashQL&#39;s point-in-time boot support with <code>versionStop</code>.</p><hr><h2 id="flashql-specific-support" tabindex="-1">FlashQL-Specific Support <a class="header-anchor" href="#flashql-specific-support" aria-label="Permalink to &quot;FlashQL-Specific Support&quot;">​</a></h2><p>Version binding is a FlashQL-oriented capability today because it depends on relation-version knowledge inside the local storage/runtime layer.</p><p>You will most commonly use it in:</p><ul><li>FlashQL queries</li><li>FlashQL joins</li><li>FlashQL historical/branching workflows</li></ul><hr><h2 id="example-bind-and-then-boot-historically" tabindex="-1">Example: Bind and Then Boot Historically <a class="header-anchor" href="#example-bind-and-then-boot-historically" aria-label="Permalink to &quot;Example: Bind and Then Boot Historically&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.snap_tbl@=1</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>In that shape:</p><ul><li><code>versionStop</code> chooses the historical replay boundary</li><li><code>@=1</code> asserts the query&#39;s relation-version expectation</li></ul><hr><h2 id="when-to-reach-for-version-binding" tabindex="-1">When to Reach for Version Binding <a class="header-anchor" href="#when-to-reach-for-version-binding" aria-label="Permalink to &quot;When to Reach for Version Binding&quot;">​</a></h2><p>Use it when:</p><ul><li>you care about schema/version safety more than silent compatibility</li><li>you are building version-aware local apps on FlashQL</li><li>you want joins to assert compatibility across multiple versioned relations</li></ul><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">FlashQL-specific language surface</td><td style="text-align:left;"><a href="/flashql/lang">FlashQL Language Surface</a></td></tr><tr><td style="text-align:left;">the broader LinkedQL language surface</td><td style="text-align:left;"><a href="/lang">Language Surface</a></td></tr></tbody></table>`,49)])])}const u=s(o,[["render",t]]);export{y as __pageData,u as default};
